<template><view class="page"><xy-header title="申请售后"/><view class="wrap"><view class="card"><text>售后原因</text><picker :range="reasons" @change="reason=reasons[$event.detail.value]"><view class="picker">{{reason||'请选择原因'}}</view></picker></view><view class="card"><text>问题说明</text><textarea v-model="description" maxlength="500" placeholder="请描述问题，便于商家处理"/></view><button class="submit" :disabled="!reason||submitting" @click="submit">{{submitting?'提交中…':'提交申请'}}</button></view></view></template>
<script>
import{appRequest,ensureMemberSession,showRequestError}from '../../utils/api'
export default{data(){return{orderNo:'',reason:'',description:'',submitting:false,reasons:['商品破损或变质','商品与描述不符','商品数量不符','其他']}},onLoad(q){this.orderNo=q.orderNo},methods:{async submit(){if(!this.orderNo)return;this.submitting=true;try{await ensureMemberSession();await appRequest({url:`/app/orders/${this.orderNo}/after-sales`,method:'POST',data:{reason:this.reason,description:this.description}});uni.showToast({title:'售后申请已提交',icon:'success'});setTimeout(()=>uni.navigateBack(),600)}catch(e){showRequestError(e)}finally{this.submitting=false}}}}
</script>
<style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.card{margin-bottom:20rpx;padding:28rpx;border-radius:22rpx;background:#fff}.picker{margin-top:22rpx;color:var(--xy-primary)}textarea{width:100%;height:220rpx;margin-top:22rpx;padding:16rpx;background:var(--xy-surface-2)}.submit{background:var(--xy-primary);color:#fff}.submit[disabled]{background:#afc4bf}</style>
